<section class="portal-page"><div class="portal-head"><div><span class="eyebrow">PATIENT PORTAL</span><h1>My Profile</h1><p>Keep your contact and emergency information accurate.</p></div><a class="btn outline" href="<?=url('dashboard')?>">Back to Dashboard</a></div><form class="hospital-form profile-form" method="post" action="<?=url('profile')?>"><?=csrf_field()?><div class="form-section"><h2>Account information</h2><div class="form-grid"><label>Full name<input name="name" value="<?=e($profile['name']??'')?>" required><small><?=e($errors['name'][0]??'')?></small></label><label>Email<input value="<?=e($profile['email']??'')?>" disabled><small>Email cannot be changed here.</small></label><label>Phone<input name="phone" value="<?=e($profile['phone']??'')?>" required><small><?=e($errors['phone'][0]??'')?></small></label><label>Date of birth<input type="date" name="date_of_birth" value="<?=e($profile['date_of_birth']??'')?>"></label><label>Gender<select name="gender"><option value="">Select</option><?php foreach(['male'=>'Male','female'=>'Female','other'=>'Other','prefer_not_to_say'=>'Prefer not to say']as$k=>$v):?><option value="<?=$k?>" <?=($profile['gender']??'')===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><label>Blood group<select name="blood_group"><option value="">Select</option><?php foreach(['A+','A-','B+','B-','AB+','AB-','O+','O-']as$b):?><option <?=($profile['blood_group']??'')===$b?'selected':''?>><?=$b?></option><?php endforeach;?></select></label></div><label>Address<textarea name="address" rows="3"><?=e($profile['address']??'')?></textarea></label></div><div class="form-section"><h2>Emergency contact</h2><div class="form-grid"><label>Contact name<input name="emergency_contact_name" value="<?=e($profile['emergency_contact_name']??'')?>"></label><label>Contact phone<input name="emergency_contact_phone" value="<?=e($profile['emergency_contact_phone']??'')?>"></label></div></div><button class="btn">Save Profile</button></form></section>

